    });

    it("accepts fractional (non-integer) timestamps", () => {
      const limiter = createLimiter(1, 1000);
      expect(limiter.allow("k", 0.5)).toBe(true);
      expect(limiter.allow("k", 1000.4)).toBe(false); // 0.5 > 0.4 → still counts
      expect(limiter.allow("k", 1000.5)).toBe(true); // 0.5 > 0.5 → expired
    });

    it("treats each timestamp against the window edge precisely", () => {
      const limiter = createLimiter(1, 100);
      expect(limiter.allow("k", 1_000_000)).toBe(true);
      expect(limiter.allow("k", 1_000_099)).toBe(false); // 1e6 > 999999 → counts
      expect(limiter.allow("k", 1_000_100)).toBe(true); // 1e6 > 1e6 is false → expired
    });
  });

  describe("invalid `now` throws TypeError", () => {
    const invalid = [
      ["undefined", undefined],
      ["null", null],
      ["a string", "0"],
      ["a numeric string", "1000"],
      ["a boolean", true],
      ["an object", {}],
      ["an array", [5]],
      ["a bigint", 10n],
      ["a function", () => 0],
      ["a Date object", new Date(0)],
      ["NaN", NaN],
      ["Infinity", Infinity],
      ["-Infinity", -Infinity],
    ];

    for (const [label, value] of invalid) {
      it(`throws TypeError when now is ${label}`, () => {
        const limiter = createLimiter(1, 1000);
        expect(() => limiter.allow("k", value)).toThrow(TypeError);
      });
    }

    it("throws when `now` is omitted entirely", () => {
      const limiter = createLimiter(1, 1000);
      expect(() => limiter.allow("k")).toThrow(TypeError);
    });

    it("does not record anything when it throws", () => {
      const limiter = createLimiter(1, 1000);
      expect(() => limiter.allow("k", NaN)).toThrow(TypeError);
      // The throwing call must not have consumed the single slot.
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 0)).toBe(false);
    });

    it("reports the offending value in the error message", () => {
      const limiter = createLimiter();
      expect(() => limiter.allow("k", "nope")).toThrow(/nope/);
    });
  });

  describe("realistic scenarios", () => {
    it("permits a steady rate at exactly the limit indefinitely", () => {
      const limiter = createLimiter(3, 1000);
      // Fire the allowed burst up front.
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 0)).toBe(false);
      // Then one call per window boundary keeps succeeding as old ones expire.
      for (let n = 1; n <= 10; n++) {
        const now = n * 1000;
        expect(limiter.allow("k", now)).toBe(true);
        expect(limiter.allow("k", now)).toBe(true);
        expect(limiter.allow("k", now)).toBe(true);
        expect(limiter.allow("k", now)).toBe(false);
      }
    });

    it("recovers full capacity after a long idle gap", () => {
      const limiter = createLimiter(2, 1000);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 0)).toBe(true);
      expect(limiter.allow("k", 0)).toBe(false);
      // Long gap well beyond the window.
      expect(limiter.allow("k", 1_000_000)).toBe(true);
      expect(limiter.allow("k", 1_000_000)).toBe(true);
      expect(limiter.allow("k", 1_000_000)).toBe(false);
    });

    it("handles many keys concurrently without cross-talk", () => {
      const limiter = createLimiter(2, 1000);
      const keys = ["u1", "u2", "u3", "u4"];
      for (const k of keys) {
        expect(limiter.allow(k, 0)).toBe(true);
        expect(limiter.allow(k, 0)).toBe(true);
        expect(limiter.allow(k, 0)).toBe(false);
      }
      // Each key independently recovers at the window edge.
      for (const k of keys) {
        expect(limiter.allow(k, 1000)).toBe(true);
      }
    });
  });
});
